#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
const int N=5e6+10,M=5e6+10,K=1e5+10,INF=0x3f3f3f3f; 
int n,m,d;
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}
	inline void Init(){memset(head,0,sizeof(head));cnt=0;}
}a,b;
int dfn[N],low[N],stk[N],bin[K],top,tob,tot[N],scc[N],dep,cnt;bool vis[K],iss[N];
long long g[K];char ch[55];inline int Cnt(int x,int y){return y*n+x;}
inline void Turn(int &x,int &y,int Q){x=(Q%n==0?n:Q%n);y=(Q-x)/n;}
inline void tarjan(int u)
{
	dfn[u]=low[u]=++dep;iss[stk[++top]=u]=1;
	grep(a,u,i)
	{
		int v=a.des[i];if(!dfn[v]){tarjan(v);low[u]=min(low[u],low[v]);}
		else if(iss[v])low[u]=min(low[u],dfn[v]);
	}
	if(dfn[u]==low[u])
	{
		int v;++cnt;do
		{
			iss[v=stk[top--]]=0;int x,y;Turn(x,y,v);scc[v]=cnt;
			if(!vis[x]&&(g[x]&(1ll<<y))){vis[bin[++tob]=x]=1;++tot[cnt];}
		}while(v^u);
	}
	while(tob)vis[bin[tob--]]=0;
}
inline int dfs(int u){int mx=0;grep(b,u,i){int v=b.des[i];mx=max(mx,dfs(v));}return mx+tot[u];}
int main()
{
	n=read();m=read();d=read();rep(1,m,i)
	{
		int x=read(),y=read();a.ins(Cnt(x,d-1),Cnt(y,0));
		rep(0,d-2,i)a.ins(Cnt(x,i),Cnt(y,i+1));
	}
	rep(1,n,i){scanf("%s",ch);rep(0,d-1,j)g[i]|=(ch[j]^48?(1ll<<j):0);}
	rep(1,n*d,i)if(!dfn[i])tarjan(i);
	rep(1,n*d,u)grep(a,u,k){int v=a.des[k];if(scc[u]^scc[v])b.ins(scc[u],scc[v]);}
	printf("%d\n",dfs(scc[1]));
}
